function clean(text) {
  if (!text) return '';

  return text
    .replace(/\s+/g, ' ')
    .replace(/\u0000/g, '')
    .trim();
}

function extractTexts(doc) {
  const texts = [];

  for (const t of doc.texts || []) {
    const text = clean(t.text || t.orig);

    if (!text) continue;

    texts.push({
      type: t.label || 'text',
      text,
      page: t.prov?.[0]?.page_no || null
    });
  }

  return texts;
}

function extractTables(doc) {
  const tables = [];

  for (const table of doc.tables || []) {

    const grid = table?.data?.grid;

    if (!Array.isArray(grid)) {
      continue;
    }

    const rows = [];

    for (const row of grid) {

      if (!Array.isArray(row)) {
        continue;
      }

      const cells = row.map(cell => {
        return clean(cell?.text || '');
      });

      // evitar filas vacías
      if (cells.some(Boolean)) {
        rows.push(cells);
      }
    }

    tables.push({
      label: table.label || 'table',
      page: table.prov?.[0]?.page_no || null,
      rows
    });
  }

  return tables;
}

function buildMarkdownTable(rows) {
  if (!rows?.length) return '';

  const md = [];

  for (const row of rows) {
    md.push(`| ${row.join(' | ')} |`);
  }

  return md.join('\n');
}

function buildChunks(doc) {

  const chunks = [];

  // TEXTS
  const texts = extractTexts(doc);

  for (const t of texts) {
    chunks.push({
      type: t.type,
      page: t.page,
      content: t.text
    });
  }

  // TABLES
  const tables = extractTables(doc);

  for (const table of tables) {

    chunks.push({
      type: 'table',
      page: table.page,
      content: buildMarkdownTable(table.rows),
      rows: table.rows
    });
  }

  return chunks;
}

// =========================
// MAIN
// =========================

const raw =
  $input.first().json.document?.json_content ||
  $input.first().json.json_content ||
  $input.first().json;

const doc =
  typeof raw === 'string'
    ? JSON.parse(raw)
    : raw;

const chunks = buildChunks(doc);

return [{
  json: {
    totalChunks: chunks.length,
    chunks
  }
}];

const data = items[0].json.data;

if (Array.isArray(data)) {
  return data.map(item => ({ json: item }));
}

return [{ json: data }];

// ========================================
// CLEANUP NODE
// ========================================

const input = items[0].json.chunks || items[0].json;

const cleaned = [];

// --------------------------------------------------
// CONFIG
// --------------------------------------------------

const REMOVE_TYPES = new Set([
  "page_header",
  "page_footer"
]);

const REMOVE_PATTERNS = [
  /^\(continúa en la pág/i,
  /^\d+$/,
  /^G\d+$/,
  /^\(\w+\)$/,
  /^02\s*\/\s*2026$/,
];

const START_PATTERN = /^Artículo\s+\d+º/i;

// --------------------------------------------------
// HELPERS
// --------------------------------------------------

function normalizeText(text) {
  return text
    .replace(/\s+/g, " ")
    .replace(/­/g, "") // soft hyphen
    .replace(/\s+([.,;:])/g, "$1")
    .trim();
}

function shouldRemoveChunk(chunk) {
  if (!chunk.content) return true;

  if (REMOVE_TYPES.has(chunk.type)) {
    return true;
  }

  const text = chunk.content.trim();

  for (const pattern of REMOVE_PATTERNS) {
    if (pattern.test(text)) {
      return true;
    }
  }

  return false;
}

// --------------------------------------------------
// MAIN
// --------------------------------------------------

let started = false;

for (const chunk of input) {

  // remove invalid chunks
  if (shouldRemoveChunk(chunk)) {
    continue;
  }

  // normalize
  const content = normalizeText(chunk.content);

  if (!content) {
    continue;
  }

  // skip everything before first article
  if (!started) {

    if (START_PATTERN.test(content)) {
      started = true;
    } else {
      continue;
    }
  }

  cleaned.push({
    type: chunk.type,
    page: chunk.page,
    content
  });
}

// --------------------------------------------------
// OUTPUT
// --------------------------------------------------

return [
  {
    json: {
      totalChunks: cleaned.length,
      chunks: cleaned
    }
  }
];

// =====================================================
// HIERARCHY BUILDER
// n8n Code Node
// =====================================================

const input = $input.first().json;

const chunks = input.chunks || [];

const hierarchy = [];
const stack = [];

// =====================================================
// HELPERS
// =====================================================

function normalize(text) {
  return (text || "")
    .replace(/\s+/g, " ")
    .trim();
}

function detectLevel(content, previousLevel = 1) {

  const text = normalize(content);

  // ==========================================
  // LEVEL 1
  // Artículo Xº
  // ==========================================

  if (/^Artículo\s+\d+/i.test(text)) {
    return 1;
  }

  // ==========================================
  // LEVEL 3
  // 1.1. Título
  // ==========================================

  if (/^\d+\.\d+\.\s*/.test(text)) {
    return 3;
  }

  // ==========================================
  // LEVEL 2
  // 1. Título
  // ==========================================

  if (/^\d+\.\s+/.test(text)) {
    return 2;
  }

  // ==========================================
  // LEVEL 4
  // ¿Qué cubre?
  // ¿Qué no cubre?
  // ==========================================

  if (/^¿Qué/i.test(text)) {
    return 4;
  }

  // ==========================================
  // SEMANTIC TITLES
  // Coberturas sin numeración
  // ==========================================

  const words = text.split(" ").length;

  const looksLikeTitle =
    words <= 8 &&
    !text.endsWith(".") &&
    !text.startsWith("-");

  if (looksLikeTitle) {

    // Después de exclusiones/cobertura
    // normalmente empieza una nueva garantía
    if (previousLevel >= 4) {
      return 2;
    }

    return previousLevel + 1;
  }

  // ==========================================
  // DEFAULT
  // ==========================================

  return 99;
}

function createNode(chunk, overrides = {}) {

  const content = normalize(chunk.content);

  return {
    type: chunk.type,
    level:
      chunk.level ||
      detectLevel(
        content,
        stack.length
          ? stack[stack.length - 1].level
          : 1
      ),
    page: chunk.page || null,
    content,
    children: [],
    ...overrides
  };
}

// =====================================================
// MAIN LOOP
// =====================================================

for (const chunk of chunks) {

  let chunkType = chunk.type || "text";

  const chunkContent = normalize(chunk.content);

  // ===================================================
  // NORMALIZE "¿QUÉ..." AS HEADERS
  // incluso si vienen como list_item/text
  // ===================================================

  if (
    /^¿Qué/i.test(chunkContent)
  ) {
    chunkType = "section_header";
  }

  // ===================================================
  // NORMALIZE SEMANTIC HEADERS
  // ===================================================

  if (
    chunkType !== "section_header"
  ) {

    const words = chunkContent.split(" ").length;

    const looksLikeSemanticTitle =
      words <= 8 &&
      !chunkContent.endsWith(".") &&
      !chunkContent.startsWith("-");

    if (looksLikeSemanticTitle) {
      chunkType = "section_header";
    }
  }

  // ===================================================
  // SECTION HEADERS
  // ===================================================

  if (chunkType === "section_header") {

    // ==========================================
    // CASO:
    // "Título ¿Qué cubre?"
    // ==========================================

    const combinedMatch =
      chunkContent.match(
        /^(.*?)\s+(¿Qué(?:\s+no)?\s+cubre.*)$/i
      );

    if (combinedMatch) {

      const parentTitle =
        normalize(combinedMatch[1]);

      const childTitle =
        normalize(combinedMatch[2]);

      const parentNode = {
        type: "section_header",
        level: detectLevel(
          parentTitle,
          stack.length
            ? stack[stack.length - 1].level
            : 1
        ),
        page: chunk.page || null,
        content: parentTitle,
        children: []
      };

      const childNode = {
        type: "section_header",
        level: 4,
        page: chunk.page || null,
        content: childTitle,
        children: []
      };

      // ==========================================
      // CLEAN STACK
      // ==========================================

      while (
        stack.length > 0 &&
        stack[stack.length - 1].level >= parentNode.level
      ) {
        stack.pop();
      }

      // ==========================================
      // INSERT PARENT
      // ==========================================

      if (stack.length === 0) {
        hierarchy.push(parentNode);
      } else {
        stack[stack.length - 1]
          .children
          .push(parentNode);
      }

      // ==========================================
      // INSERT CHILD
      // ==========================================

      parentNode.children.push(childNode);

      // ==========================================
      // PUSH TO STACK
      // ==========================================

      stack.push(parentNode);
      stack.push(childNode);

      continue;
    }

    // ==========================================
    // NORMAL HEADER
    // ==========================================

    const node = createNode({
      ...chunk,
      type: chunkType
    });

    // ==========================================
    // CLEAN STACK
    // ==========================================

    while (
      stack.length > 0 &&
      stack[stack.length - 1].level >= node.level
    ) {
      stack.pop();
    }

    // ==========================================
    // INSERT NODE
    // ==========================================

    if (stack.length === 0) {
      hierarchy.push(node);
    } else {
      stack[stack.length - 1]
        .children
        .push(node);
    }

    // ==========================================
    // PUSH HEADER ONLY
    // ==========================================

    stack.push(node);

    continue;
  }

  // ===================================================
  // TEXT / LIST_ITEM / PARAGRAPH
  // ===================================================

  const leaf = {
    type: chunkType,
    page: chunk.page || null,
    content: chunkContent
  };

  if (stack.length === 0) {
    hierarchy.push(leaf);
  } else {
    stack[stack.length - 1]
      .children
      .push(leaf);
  }
}

// =====================================================
// OUTPUT
// =====================================================

return [
  {
    json: {
      hierarchy
    }
  }
];

// ============================================
// SEMANTIC ASSEMBLER
// n8n Code Node
// ============================================

const input = $input.first().json;

const hierarchy = input.hierarchy || [];

const semanticUnits = [];

let idCounter = 1;

// ============================================
// SECTION DETECTION
// ============================================

function detectSectionType(text = "") {
  const t = text.toLowerCase();

  if (/(qué no cubre|no cubre|exclusiones?)/i.test(t)) {
    return "exclusion";
  }

  if (/(qué cubre|coberturas?|garantías?)/i.test(t)) {
    return "coverage";
  }

  if (/(límites?|limitaciones?|sublímites?)/i.test(t)) {
    return "limit";
  }

  if (/(franquicias?|deducible)/i.test(t)) {
    return "deductible";
  }

  if (/(condiciones?|requisitos?)/i.test(t)) {
    return "condition";
  }

  if (/(ámbito territorial|territorial)/i.test(t)) {
    return "territorial_scope";
  }

  return null;
}

// ============================================
// COVERAGE HEADER DETECTION
// ============================================

function isCoverageHeader(text = "") {
  if (!text) return false;

  if (detectSectionType(text)) {
    return false;
  }

  const t = text.trim();

  // Numeric coverage patterns
  if (/^\d+(\.\d+)*\.?\s+/.test(t)) {
    return true;
  }

  // Common coverage patterns
  if (/(garantía|cobertura|protección|asistencia)/i.test(t)) {
    return true;
  }

  return true;
}

// ============================================
// SEMANTIC TYPE DETECTION
// ============================================

function detectSemanticType(text = "", currentSection = null) {

  const t = text.toLowerCase();

  // EXCLUSION
  if (
    /(no cubre|no quedan cubiertos|queda excluido|se excluye|esta cobertura no|no se garantiza)/i.test(t)
  ) {
    return "exclusion";
  }

  // DEDUCTIBLE
  if (
    /(franquicia|deducible|a cargo del asegurado)/i.test(t)
  ) {
    return "deductible";
  }

  // LIMIT
  if (
    /(hasta|máximo|con el límite|no superior a|hasta un máximo)/i.test(t)
  ) {
    return "limit";
  }

  // CONDITION
  if (
    /(siempre que|cuando se asegure|en caso de|a condición de|si )/i.test(t)
  ) {
    return "condition";
  }

  // DEPENDENCY
  if (
    /(siempre que esté contratada|requiere la contratación|solo si se incluye)/i.test(t)
  ) {
    return "dependency";
  }

  // TERRITORIAL
  if (
    /(territorio|españa|unión europea|extranjero|ámbito territorial)/i.test(t)
  ) {
    return "territorial_scope";
  }

  // REQUIREMENT
  if (
    /(deberá|será necesario|obligatorio|requiere)/i.test(t)
  ) {
    return "requirement";
  }

  // SECTION FALLBACK
  if (currentSection) {
    return currentSection;
  }

  return "unknown";
}

// ============================================
// TEXT NORMALIZATION
// ============================================

function normalizeText(text) {
  return text
    .replace(/\s+/g, " ")
    .replace(/\s([.,;:])/g, "$1")
    .trim();
}

// ============================================
// EMIT SEMANTIC UNIT
// ============================================

function emitSemanticUnit(context, text, sourceHeaders = []) {

  const normalized = normalizeText(text);

  if (!normalized) return;

  const semanticType = detectSemanticType(
    normalized,
    context.currentSection
  );

  semanticUnits.push({
    id: `su_${String(idCounter++).padStart(5, "0")}`,

    article: context.article || null,

    coverage_path: [...context.coveragePath],

    section: context.currentSection || "unknown",

    semantic_type: semanticType,

    text: normalized,

    source_headers: sourceHeaders,

    lineage: [
      context.article,
      ...context.coveragePath
    ].filter(Boolean),

    metadata: {
      contains_limits:
        semanticType === "limit",

      contains_conditions:
        semanticType === "condition",

      contains_exclusions:
        semanticType === "exclusion",

      word_count:
        normalized.split(/\s+/).length
    }
  });
}

// ============================================
// CONSOLIDATE TEXT CHILDREN
// ============================================

function consolidateTextNodes(children = []) {

  const blocks = [];

  let currentBlock = [];

  function flush() {

    if (currentBlock.length) {

      blocks.push({
        type: "text_block",
        content: currentBlock.join("\n")
      });

      currentBlock = [];
    }
  }

  for (const child of children) {

    // TEXT NODES
    if (
      child.type === "text" ||
      child.type === "paragraph"
    ) {
      currentBlock.push(child.content);
      continue;
    }

    // LIST ITEMS
    if (child.type === "list_item") {

      currentBlock.push(`- ${child.content}`);
      continue;
    }

    // STRUCTURAL NODE
    flush();

    blocks.push(child);
  }

  flush();

  return blocks;
}

// ============================================
// DFS WALKER
// ============================================

function walk(node, parentContext = {}) {

  const context = {
    article: parentContext.article || null,
    coveragePath: [...(parentContext.coveragePath || [])],
    currentSection: parentContext.currentSection || null
  };

  // ========================================
  // SECTION HEADERS
  // ========================================

  if (node.type === "section_header") {

    const header = normalizeText(node.content);

    // ARTICLE
    if (/^artículo/i.test(header)) {

      context.article = header;
    }

    // SEMANTIC SECTION
    const detectedSection = detectSectionType(header);

    if (detectedSection) {

      context.currentSection = detectedSection;
    }
    else {

      // COVERAGE HEADER
      if (isCoverageHeader(header)) {

        context.coveragePath.push(header);
      }
    }
  }

  // ========================================
  // CHILD CONSOLIDATION
  // ========================================

  const children = consolidateTextNodes(node.children || []);

  // ========================================
  // PROCESS CHILDREN
  // ========================================

  for (const child of children) {

    // CONSOLIDATED TEXT BLOCK
    if (child.type === "text_block") {

      emitSemanticUnit(
        context,
        child.content,
        [...context.coveragePath]
      );

      continue;
    }

    // RECURSIVE DESCENT
    walk(child, context);
  }
}

// ============================================
// ROOT WALK
// ============================================

for (const node of hierarchy) {
  walk(node, {});
}

// ============================================
// OUTPUT
// ============================================

return [
  {
    json: {
      semantic_units: semanticUnits
    }
  }
];

// =====================================================
// ONTOLOGY EMBEDDING BUILDER
// n8n Code Node
// =====================================================

const input = $input.first().json;

const semanticUnits = input.semantic_units || [];

const embeddingDocuments = [];

// =====================================================
// HELPERS
// =====================================================

function normalize(text) {
  return (text || "")
    .replace(/\s+/g, " ")
    .trim();
}

function buildEmbeddingText(unit) {

  const parts = [];

  // ==========================================
  // ARTICLE
  // ==========================================

  if (unit.article) {
    parts.push(`Artículo: ${normalize(unit.article)}`);
  }

  // ==========================================
  // COVERAGE PATH
  // ==========================================

  if (
    Array.isArray(unit.coverage_path) &&
    unit.coverage_path.length > 0
  ) {
    parts.push(
      `Cobertura: ${unit.coverage_path.join(" > ")}`
    );
  }

  // ==========================================
  // SECTION
  // ==========================================

  if (unit.section) {
    parts.push(`Sección: ${unit.section}`);
  }

  // ==========================================
  // SEMANTIC TYPE
  // ==========================================

  if (unit.semantic_type) {
    parts.push(
      `Tipo semántico: ${unit.semantic_type}`
    );
  }

  // ==========================================
  // SOURCE HEADERS
  // ==========================================

  if (
    Array.isArray(unit.source_headers) &&
    unit.source_headers.length > 0
  ) {
    parts.push(
      `Headers: ${unit.source_headers.join(" > ")}`
    );
  }

  // ==========================================
  // LINEAGE
  // ==========================================

  if (
    Array.isArray(unit.lineage) &&
    unit.lineage.length > 0
  ) {
    parts.push(
      `Jerarquía: ${unit.lineage.join(" > ")}`
    );
  }

  // ==========================================
  // LEGAL TEXT
  // ==========================================

  if (unit.text) {
    parts.push(
      `Texto jurídico: ${normalize(unit.text)}`
    );
  }

  return parts.join("\n");
}

// =====================================================
// MAIN LOOP
// =====================================================

for (const unit of semanticUnits) {

  const embeddingText = buildEmbeddingText(unit);

  embeddingDocuments.push({

    id: unit.id,

    embedding_text: embeddingText,

    semantic_unit: unit

  });
}

// =====================================================
// OUTPUT
// =====================================================

return [
  {
    json: {
      total_documents: embeddingDocuments.length,
      embedding_documents: embeddingDocuments
    }
  }
];

const itemsOut = [];

/**
 * =========================================================
 * RULE CHUNKER v4.1 STABLE
 * =========================================================
 *
 * NUEVO:
 * ✔ excluyéndose → excludes
 * ✔ con exclusión de → excludes
 * ✔ únicamente → requires
 *
 * =========================================================
 *
 * OBJETIVO:
 * Crear chunks jurídicos coherentes y enriquecidos
 * para el extractor LLM.
 *
 * =========================================================
 */


// =========================================================
// CONFIG
// =========================================================

const MIN_CHUNK_LENGTH = 25;


// =========================================================
// HELPERS
// =========================================================

function cleanText(text) {

  return text
    .replace(/\s+/g, " ")
    .replace(/\n+/g, "\n")
    .trim();
}


// =========================================================
// SENTENCE SPLITTER
// =========================================================

function splitIntoSentences(text) {

  return text
    .split(
      /(?<=[.;:])\s+|\n+/g
    )
    .map(s => s.trim())
    .filter(Boolean);
}


// =========================================================
// BULLET SPLITTER
// =========================================================

function splitBullets(text) {

  const normalized =
    text
      .replace(/\s+-\s+/g, "\n- ")
      .replace(/\s+•\s+/g, "\n• ");

  const bulletRegex =
    /(?:^|\n)\s*[-•·▪◦]\s+/g;

  const hasBullets =
    bulletRegex.test(normalized);

  if (!hasBullets) {
    return [normalized];
  }

  return normalized
    .split(bulletRegex)
    .map(t => t.trim())
    .filter(t => t.length > 20);
}


// =========================================================
// ENUMERATION-AWARE LEGAL UNIT
// =========================================================

function isStandaloneLegalBullet(text) {

  const t = text.toLowerCase();

  // -------------------------------------------------------
  // limits
  // -------------------------------------------------------

  const hasLimit =
    /\b(hasta|maximo|máximo|mínimo)\b/i.test(t) ||
    /\b\d+[.,]?\d*\s?(€|euros|%)\b/i.test(t);

  // -------------------------------------------------------
  // conditions
  // -------------------------------------------------------

  const hasCondition =
    t.includes("siempre que") ||
    t.includes("a condición de") ||
    t.includes("condicionado a") ||
    t.includes("únicamente");

  // -------------------------------------------------------
  // exclusions
  // -------------------------------------------------------

  const hasNegation =
    t.includes("salvo") ||
    t.includes("no se aplica") ||
    t.includes("quedan excluidos") ||
    t.includes("con exclusión de") ||
    t.includes("excluyéndose");

  // -------------------------------------------------------
  // density
  // -------------------------------------------------------

  const longEnough =
    text.length > 60;

  return (
    longEnough &&
    (
      hasLimit ||
      hasCondition ||
      hasNegation
    )
  );
}


// =========================================================
// LEGAL BOUNDARY DETECTION
// =========================================================

function startsNewLegalChunk(sentence) {

  const s = sentence.toLowerCase();

  return (

    s.startsWith("salvo ") ||

    s.startsWith("siempre que") ||

    s.startsWith("a condición de") ||

    s.startsWith("quedan excluidos") ||

    s.startsWith("no se cubre") ||

    s.startsWith("no se aplica") ||

    s.startsWith("con exclusión de") ||

    s.startsWith("excluyéndose") ||

    s.startsWith("hasta el") ||

    s.startsWith("hasta ") ||

    s.startsWith("máximo ") ||

    s.startsWith("mínimo ") ||

    s.startsWith("únicamente") ||

    /\b\d+[.,]?\d*\s?(€|euros|%)\b/i.test(s)

  );
}


// =========================================================
// MULTI-CUE DETECTION
// =========================================================

function detectAllCues(text) {

  const t = text.toLowerCase();

  const detected = [];

  // -------------------------------------------------------
  // NEGATION / EXCEPTION
  // -------------------------------------------------------

  if (
    t.includes("salvo") ||
    t.includes("a menos que")
  ) {
    detected.push("negation");
  }

  // -------------------------------------------------------
  // EXCLUSION
  // -------------------------------------------------------

  if (
    t.includes("quedan excluidos") ||
    t.includes("no se cubre") ||
    t.includes("no estarán cubiertos") ||
    t.includes("no quedará cubierta") ||
    t.includes("no se aplica") ||
    t.includes("con exclusión de") ||
    t.includes("excluyéndose") ||
    t.includes("excluidos")
  ) {
    detected.push("excludes");
  }

  // -------------------------------------------------------
  // REQUIRES
  // -------------------------------------------------------

  if (
    t.includes("siempre que") ||
    t.includes("a condición de") ||
    t.includes("condicionado a") ||
    t.includes("únicamente")
  ) {
    detected.push("requires");
  }

  // -------------------------------------------------------
  // TEMPORAL LIMIT
  // -------------------------------------------------------

  if (
    /\b(más de|menos de|inferior a|superior a)\s+\d+\s+(días|meses|años)\b/i.test(t)
  ) {
    detected.push("temporal_limit");
  }

  // -------------------------------------------------------
  // LIMIT
  // -------------------------------------------------------

  if (
    /\bhasta el\s+\d+/i.test(t) ||
    /\b\d+[.,]?\d*\s?(€|euros|%)\b/i.test(t)
  ) {
    detected.push("limit");
  }

  // -------------------------------------------------------
  // DEPENDENCY
  // -------------------------------------------------------

  if (
    t.includes("depende de") ||
    t.includes("supeditado")
  ) {
    detected.push("depends_on");
  }

  // -------------------------------------------------------
  // FALLBACK
  // -------------------------------------------------------

  if (detected.length === 0) {
    detected.push("generic_rule");
  }

  return detected;
}


// =========================================================
// PRIMARY CUE
// =========================================================

function computePrimaryCue(cues) {

  const precedence = {

    excludes: 100,

    negation: 95,

    temporal_limit: 90,

    limit: 80,

    requires: 70,

    depends_on: 60,

    generic_rule: 10
  };

  let bestCue = "generic_rule";

  let bestScore = 0;

  for (const cue of cues) {

    const score =
      precedence[cue] || 0;

    if (score > bestScore) {

      bestScore = score;

      bestCue = cue;
    }
  }

  return bestCue;
}


// =========================================================
// CHUNK TYPE
// =========================================================

function detectChunkType(primaryCue) {

  switch (primaryCue) {

    case "limit":
      return "limit_rule";

    case "temporal_limit":
      return "temporal_limit_rule";

    case "requires":
      return "condition_rule";

    case "excludes":
      return "exclusion_rule";

    case "negation":
      return "exception_rule";

    case "depends_on":
      return "dependency_rule";

    default:
      return "generic_rule";
  }
}


// =========================================================
// CHUNK PRIORITY
// =========================================================

function computeChunkPriority(
  allCues,
  text
) {

  let score = 1;

  // -------------------------------------------------------
  // cue density
  // -------------------------------------------------------

  score += allCues.length;

  // -------------------------------------------------------
  // exclusions
  // -------------------------------------------------------

  if (
    allCues.includes("excludes") ||
    allCues.includes("negation")
  ) {
    score += 3;
  }

  // -------------------------------------------------------
  // conditions
  // -------------------------------------------------------

  if (
    allCues.includes("requires")
  ) {
    score += 2;
  }

  // -------------------------------------------------------
  // limits
  // -------------------------------------------------------

  if (
    allCues.includes("limit") ||
    allCues.includes("temporal_limit")
  ) {
    score += 2;
  }

  // -------------------------------------------------------
  // numeric density
  // -------------------------------------------------------

  const numericMatches =
    text.match(/\d+/g) || [];

  score += Math.min(
    numericMatches.length,
    3
  );

  // -------------------------------------------------------
  // long chunks
  // -------------------------------------------------------

  if (text.length > 250) {
    score += 1;
  }

  return score;
}


// =========================================================
// CHUNK COMPLEXITY
// =========================================================

function detectChunkComplexity(allCues) {

  if (allCues.length >= 4) {
    return "nested";
  }

  if (allCues.length >= 2) {
    return "compound";
  }

  return "simple";
}


// =========================================================
// BUILD CHUNK
// =========================================================

function buildChunk(
  chunkText,
  semanticUnitId,
  chunkCounter
) {

  const cleanChunk =
    cleanText(chunkText);

  // -------------------------------------------------------
  // multi-cue detection
  // -------------------------------------------------------

  const allDetectedCues =
    detectAllCues(cleanChunk);

  const primaryCue =
    computePrimaryCue(allDetectedCues);

  const secondaryCues =
    allDetectedCues.filter(
      c => c !== primaryCue
    );

  return {

    chunk_id:
      `${semanticUnitId}_c${chunkCounter}`,

    chunk_type:
      detectChunkType(primaryCue),

    primary_cue:
      primaryCue,

    secondary_cues:
      secondaryCues,

    all_detected_cues:
      allDetectedCues,

    chunk_complexity:
      detectChunkComplexity(
        allDetectedCues
      ),

    chunk_priority:
      computeChunkPriority(
        allDetectedCues,
        cleanChunk
      ),

    text:
      cleanChunk
  };
}


