function boostConfidence(
  baseConfidence,
  semanticType,
  section,
  cueType
) {

  let boosted = baseConfidence;

  // -------------------------------------------------------
  // semantic priors
  // -------------------------------------------------------

  if (
    semanticType === "exclusion" &&
    (
      cueType === "excludes" ||
      cueType === "excludes_if" ||
      cueType === "negation"
    )
  ) {
    boosted += 0.05;
  }

  if (
    semanticType === "condition" &&
    cueType === "requires"
  ) {
    boosted += 0.04;
  }

  if (
    semanticType === "limit" &&
    (
      cueType === "limit" ||
      cueType === "temporal_limit"
    )
  ) {
    boosted += 0.05;
  }

  // -------------------------------------------------------
  // section priors
  // -------------------------------------------------------

  if (
    section === "territorial_scope" &&
    cueType === "limit"
  ) {
    boosted += 0.04;
  }

  // -------------------------------------------------------
  // clamp
  // -------------------------------------------------------

  if (boosted > 0.99) {
    boosted = 0.99;
  }

  return Number(boosted.toFixed(2));
}


// =========================================================
// DETECT LIMIT SUBTYPE
// =========================================================

function detectLimitSubtype(text) {

  const t = text.toLowerCase();

  if (
    t.includes("día") ||
    t.includes("días") ||
    t.includes("mes") ||
    t.includes("meses") ||
    t.includes("año") ||
    t.includes("años")
  ) {
    return "temporal_limit";
  }

  return "limit";
}


// =========================================================
// OVERLAP DETECTION
// =========================================================

function hasOverlap(existingMatches, start, end) {

  return existingMatches.some(existing => {

    return (
      start < existing.end &&
      end > existing.start
    );
  });
}


// =========================================================
// SUPPRESS REDUNDANT WEAK LIMITS
// =========================================================

function hasNearbyStrongLimit(matches, start) {

  return matches.some(m => {

    return (
      (
        m.type === "limit" ||
        m.type === "temporal_limit"
      ) &&
      m.strength === "strong" &&
      Math.abs(m.start - start) < 25
    );
  });
}


// =========================================================
// SUPPRESS MAX/MIN
// NEAR NUMERIC LIMITS
// =========================================================

function hasNearbyNumericLimit(matches, start) {

  return matches.some(m => {

    return (
      (
        m.type === "limit" ||
        m.type === "temporal_limit"
      ) &&
      m.strength === "strong" &&
      Math.abs(m.start - start) < 60
    );
  });
}


