  const strongCueCount =
    cueMatches.filter(c => c.strength === "strong").length;

  const hasNegation =
    cueTypes.includes("negation");

  const hasMultipleCueTypes =
    cueTypes.length > 1;

  if (
    hasNegation &&
    hasMultipleCueTypes
  ) {
    return "nested";
  }

  if (
    hasMultipleCueTypes ||
    strongCueCount > 1
  ) {
    return "compound";
  }

  return "simple";
}


