  ];

  const strongestConfidence =
    cueMatches.length > 0
      ? Math.max(...cueMatches.map(c => c.confidence))
      : 0;

  const strongCueCount =
    cueMatches.filter(c => c.strength === "strong").length;

  const distinctLimitTexts = [
    ...new Set(
      cueMatches
        .filter(c =>
          c.type === "limit" ||
          c.type === "temporal_limit"
        )
        .map(c => c.text.toLowerCase())
    )
  ];

  /**
   * IMPORTANTE:
   * útil para Rule Chunker
   * y reducción de complejidad artificial
   */

  const distinctCueTexts = [
    ...new Set(
      cueMatches.map(c => c.text.toLowerCase())
    )
  ];

  const implicitExclusionCandidate =
    semanticType === "exclusion" &&
    cueMatches.length === 0;

  // =====================================================
  // OUTPUT
  // =====================================================

  itemsOut.push({

    json: {

      semantic_unit_id: su.id,

      article: su.article,

      section,

      semantic_type: semanticType,

      coverage_path: coveragePath,

      lineage,

      text,

      metadata: su.metadata || {},

      ontology_matches: item.json.ontology_matches || [],

      ontology_match_count: 
        (item.json.ontology_matches || []).length,

      legal_cue_analysis: {

        has_legal_cues:
          cueMatches.length > 0,

        cue_types: cueTypes,

        cue_matches: cueMatches,

        complexity:
          detectComplexity(cueMatches),

        cue_confidence:
          strongestConfidence,

        strong_cue_count:
          strongCueCount,

        distinct_cue_types_count:
          cueTypes.length,

        distinct_limit_values:
          distinctLimitTexts.length,

        distinct_cue_texts_count:
          distinctCueTexts.length,

        implicit_exclusion_candidate:
          implicitExclusionCandidate,

        should_call_llm:
          shouldCallLLM(
            cueMatches,
            semanticType
          )
      }
    }
  });
}

return itemsOut;

/**
 * Should Call LLM Filter
 *
 * Mantiene únicamente semantic units
 * marcadas por el Candidate Detector.
 */

return items.filter(item => {

  return (
    item.json.legal_cue_analysis?.should_call_llm === true
  );

});

const artifacts = items
  .map(item => item.json)
  .filter(artifact =>
    artifact.has_dependencies === true
  );

const totalSemanticUnits = items.length;

return [{
  json: {

    schema_version: "1.0",

    generated_at:
      new Date().toISOString(),

    total_semantic_units:
      totalSemanticUnits,

    artifact_count:
      artifacts.length,

    artifacts

  }
}];

const timestamp = new Date()
  .toISOString()
  .replace(/[:.]/g, '-');

return [{
  json: {
    ...$json,
    filename: `coverage_matcher_contract_${timestamp}.json`
  }
}];
